import{_ as a,o,c as t,ag as r}from"./chunks/framework.B45ElpZ1.js";const f=JSON.parse('{"title":"PMS and Portfolio Workflows","description":"Portfolio-level decisions across brokers, mandates, weights, concentration, correlation, rebalancing, and tax harvesting.","frontmatter":{"title":"PMS and Portfolio Workflows","description":"Portfolio-level decisions across brokers, mandates, weights, concentration, correlation, rebalancing, and tax harvesting.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/portfolio-manager"}]]},"headers":[],"relativePath":"guides/portfolio-manager.md","filePath":"guides/portfolio-manager.md"}'),i={name:"guides/portfolio-manager.md"};function s(n,e,l,c,d,p){return o(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="pms-and-portfolio-workflows" tabindex="-1">PMS and Portfolio Workflows <a class="header-anchor" href="#pms-and-portfolio-workflows" aria-label="Permalink to &quot;PMS and Portfolio Workflows&quot;">​</a></h1><p>PMS workflows are portfolio-level Office Mode work: mandates, weights, sectors, concentration, drawdown, correlation, and review cadence. The desk uses specialist workers when needed, while AITradingOffice keeps the durable record.</p><h2 id="what-it-s-for" tabindex="-1">What it&#39;s for <a class="header-anchor" href="#what-it-s-for" aria-label="Permalink to &quot;What it&#39;s for&quot;">​</a></h2><ul><li>Snapshots across Groww + Kite in one view</li><li>Allocation review and rebalancing plans</li><li>Position review with decision categories (keep / trim / add / exit / watch)</li><li>Tax harvesting, earnings calendar prep, IPO tracking</li><li>New-buy checklists that include portfolio-fit checks</li></ul><h2 id="primary-tools" tabindex="-1">Primary tools <a class="header-anchor" href="#primary-tools" aria-label="Permalink to &quot;Primary tools&quot;">​</a></h2><ul><li>MCP-backed broker tools (Groww, Zerodha Kite) for live holdings, positions, margins</li><li>XLSX import for portfolios held elsewhere</li><li>Browser for broker UI actions a skill walks through</li><li>AITradingOffice records for theses, ledgers, reviews, clients, and office state</li></ul><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Run <code>tradecli setup</code>, launch <code>tradecli</code>, then choose a PMS or portfolio workflow from the interactive TUI. Broker login can happen on first use when a workflow needs account data.</p><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Show my portfolio</span></span>
<span class="line"><span>Allocation review — am I overweight anywhere?</span></span>
<span class="line"><span>Rebalance plan for my target 60% equity / 30% debt / 10% cash</span></span>
<span class="line"><span>Tax harvesting ideas for FY26</span></span>
<span class="line"><span>New buy checklist for BAJFINANCE</span></span>
<span class="line"><span>Which of my holdings have results next week?</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Read-only by default</p><p>PMS workflows surface decisions but do not execute orders automatically. Any action that moves money requires explicit user authorization at the broker. Claims of &quot;deployed&quot; or &quot;placed&quot; only appear when a tool confirms execution.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Compare with other personas</strong> → <a href="/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Connect brokers</strong> → <a href="./../getting-started/broker-setup">Broker Setup</a> — Groww and Zerodha Kite first-use behavior</li></ul>`,13)])])}const u=a(i,[["render",s]]);export{f as __pageData,u as default};
